import { useState, useRef, useEffect } from "react";

const GROQ_API_URL = "/openai/v1/chat/completions";
const GROQ_API_KEY = "YOUR_GROQ_KEY_HERE"; // 🔴 paste your gsk_... key here

export default function AudioCallTab({ topic, language }) {
  const [messages,   setMessages]   = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [listening,  setListening]  = useState(false);
  const [transcript, setTranscript] = useState("");
  const [callActive, setCallActive] = useState(false);
  const [ariaStatus, setAriaStatus] = useState("idle");
  const [textInput,  setTextInput]  = useState("");
  const recognitionRef = useRef(null);
  const synthRef       = useRef(window.speechSynthesis);
  const transcriptRef  = useRef("");
  const messagesEndRef = useRef(null);

  function getLangCode(code) {
    const map = { es: "es-ES", fr: "fr-FR", de: "de-DE", ja: "ja-JP", pt: "pt-PT" };
    return map[code] || "en-US";
  }

  // Auto scroll messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Setup Speech Recognition
  useEffect(() => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) return;
    const recognition        = new SR();
    recognition.continuous     = false;
    recognition.interimResults = true;
    recognition.lang           = getLangCode(language?.code);

    recognition.onresult = (e) => {
      const t = Array.from(e.results).map(r => r[0].transcript).join("");
      transcriptRef.current = t;
      setTranscript(t);
    };

    recognition.onend = () => {
      setListening(false);
      const finalText = transcriptRef.current.trim();
      transcriptRef.current = "";
      setTranscript("");
      if (finalText) sendToAria(finalText);
      else setAriaStatus("idle");
    };

    recognition.onerror = (e) => {
      console.error("Speech error:", e.error);
      setListening(false);
      setAriaStatus("idle");
    };

    recognitionRef.current = recognition;
  }, [language]);

  function startCall() {
    setCallActive(true);
    setMessages([]);
    setAriaStatus("idle");
    speakAria(`Hello! I'm Aria. Let's practice ${topic}. You can speak or type!`);
  }

  function endCall() {
    setCallActive(false);
    setAriaStatus("idle");
    synthRef.current.cancel();
    if (recognitionRef.current) recognitionRef.current.abort();
  }

  function startListening() {
    if (!recognitionRef.current || loading || ariaStatus === "thinking") return;
    synthRef.current.cancel();
    transcriptRef.current = "";
    setTranscript("");
    setListening(true);
    setAriaStatus("listening");
    try { recognitionRef.current.start(); }
    catch(e) { setListening(false); setAriaStatus("idle"); }
  }

  function stopListening() {
    if (recognitionRef.current && listening) recognitionRef.current.stop();
  }

  async function sendToAria(text) {
    setMessages(prev => [...prev, { role: "user", text }]);
    setAriaStatus("thinking");
    setLoading(true);

    try {
      const res = await fetch(GROQ_API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${GROQ_API_KEY}`
        },
        body: JSON.stringify({
          model: "llama-3.3-70b-versatile",
          messages: [
            {
              role: "system",
              content: `You are Aria, a friendly conversational language tutor.
Topic: ${topic}. Student is learning: ${language?.name || "a language"}.
Rules:
- Respond in ONLY 1-3 short sentences to maintain natural conversation pace.
- Respond in ${language?.name || "the target language"} with English hints in [brackets] only when needed.
- Gently correct errors inline without stopping the conversation.
- Never go off topic. If off topic say: "Let's stay focused on our lesson!"`
            },
            { role: "user", content: text }
          ],
          max_tokens: 120,
          temperature: 0.8
        }),
      });

      const data  = await res.json();
      const reply = data?.choices?.[0]?.message?.content || "Sorry, I didn't catch that.";
      setMessages(prev => [...prev, { role: "aria", text: reply }]);
      speakAria(reply);

    } catch (err) {
      setMessages(prev => [...prev, { role: "aria", text: "Sorry, something went wrong." }]);
      setAriaStatus("idle");
    }

    setLoading(false);
  }

  function speakAria(text) {
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang  = getLangCode(language?.code);
    utterance.rate  = 0.95;
    utterance.pitch = 1.1;
    setAriaStatus("speaking");
    utterance.onend = () => setAriaStatus("idle");
    synthRef.current.speak(utterance);
  }

  function sendTextMessage() {
    if (!textInput.trim() || loading) return;
    const text = textInput.trim();
    setTextInput("");
    sendToAria(text);
  }

  const statusLabel = {
    idle:      "Hold 🎙 to speak — or type below",
    listening: "🔴 Listening... release when done",
    thinking:  "💭 Aria is thinking...",
    speaking:  "🔊 Aria is speaking...",
  }[ariaStatus];

  return (
    <div className="call-container">
      {!callActive ? (
        <div className="call-idle">
          <div className="call-avatar">🤖</div>
          <p className="call-aria-name">Aria</p>
          <p className="call-topic">Topic: <strong>{topic}</strong></p>
          <p className="call-lang">Language: <strong>{language?.name}</strong></p>
          <button className="call-start-btn" onClick={startCall}>
            📞 Start Call
          </button>
        </div>
      ) : (
        <div className="call-active">
          <div className="call-messages">
            {messages.map((msg, i) => (
              <div key={i} className={`call-bubble ${msg.role}`}>
                {msg.role === "aria" && <span className="call-name">Aria</span>}
                <p>{msg.text}</p>
              </div>
            ))}
            {ariaStatus === "thinking" && (
              <div className="call-bubble aria">
                <span className="call-name">Aria</span>
                <p className="typing">● ● ●</p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="call-controls">
            <p className="call-status">{statusLabel}</p>
            {transcript && <p className="call-transcript">"{transcript}"</p>}
            <button
              className={`call-mic-btn ${listening ? "active" : ""}`}
              onMouseDown={startListening}
              onMouseUp={stopListening}
              onTouchStart={(e) => { e.preventDefault(); startListening(); }}
              onTouchEnd={(e)   => { e.preventDefault(); stopListening();  }}
              disabled={ariaStatus === "thinking" || ariaStatus === "speaking"}
            >
              {listening ? "🔴" : "🎙"}
            </button>
            <button className="call-end-btn" onClick={endCall}>📵 End Call</button>
          </div>

          {/* Text input as fallback */}
          <div className="chat-input-row">
            <input
              className="chat-input"
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && sendTextMessage()}
              placeholder="Or type your message..."
              disabled={loading}
            />
            <button className="chat-send" onClick={sendTextMessage}>➤</button>
          </div>
        </div>
      )}
    </div>
  );
}
